 98→/** List active decisions, optionally scoped to a project and/or area */
 99→export async function listProjectDecisions(input: {
100→  surreal: Surreal;
101→  workspaceRecord: RecordId<"workspace", string>;
102→  projectRecord?: RecordId<"project", string>;
103→  area?: string;
104→}): Promise<{
105→  confirmed: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
106→  provisional: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
107→  contested: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
108→}> {
109→  const projectFilter = input.projectRecord
110→    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
111→    : "";
112→  const areaFilter = input.area
113→    ? `AND category = $area`
114→    : "";
115→
116→  const [rows] = await input.surreal
117→    .query<[DecisionRow[]]>(
118→      `SELECT id, summary, status, rationale, decided_at, category, priority, created_at
119→       FROM decision
120→       WHERE workspace = $workspace
121→         ${projectFilter}
122→         ${areaFilter}
123→       ORDER BY created_at DESC LIMIT 50;`,
124→      {
125→        workspace: input.workspaceRecord,
126→        ...(input.projectRecord ? { project: input.projectRecord } : {}),
127→        ...(input.area ? { area: input.area } : {}),
128→      },
129→    )
130→    .collect<[DecisionRow[]]>();
131→
132→  type DecisionItem = { id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string };
133→  const confirmed: DecisionItem[] = [];
134→  const provisional: DecisionItem[] = [];
135→  const contested: DecisionItem[] = [];
136→
137→  for (const d of rows) {
138→    const item: DecisionItem = {
139→      id: toRawId(d.id),
140→      summary: d.summary,
141→      status: d.status,
142→      ...(d.rationale ? { rationale: d.rationale } : {}),
143→      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
144→      ...(d.category ? { category: d.category } : {}),
145→    };
146→
147→    if (d.status === "contested") contested.push(item);
148→    else if (d.status === "provisional" || d.status === "inferred") provisional.push(item);
149→    else if (d.status === "confirmed") confirmed.push(item);
150→  }
151→
152→  return { confirmed, provisional, contested };
153→}
