324→/** Create a subtask with semantic dedup */
325→export async function createSubtask(input: {
326→  surreal: Surreal;
327→  parentTaskRecord: RecordId<"task", string>;
328→  title: string;
329→  workspaceRecord: RecordId<"workspace", string>;
330→  category?: string;
331→  rationale?: string;
332→}): Promise<{ task_id: string; parent_task_id: string; already_existed: boolean }> {
333→  // Check for existing similar subtasks (semantic dedup by title)
334→  const normalizedTitle = input.title.toLowerCase().trim();
335→
336→  const [existingRows] = await input.surreal
337→    .query<[SubtaskRow[]]>(
338→      `SELECT id, title, status
339→       FROM task
340→       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent)
341→       ORDER BY created_at ASC;`,
342→      { parent: input.parentTaskRecord },
343→    )
344→    .collect<[SubtaskRow[]]>();
345→
346→  // Simple dedup: check if any existing subtask title is very similar
347→  for (const existing of existingRows) {
348→    const existingNormalized = existing.title.toLowerCase().trim();
349→    if (existingNormalized === normalizedTitle || levenshteinSimilarity(existingNormalized, normalizedTitle) > 0.85) {
350→      return {
351→        task_id: toRawId(existing.id),
352→        parent_task_id: toRawId(input.parentTaskRecord),
353→        already_existed: true,
354→      };
355→    }
356→  }
357→
358→  // Get parent task's category if not specified
359→  const parentTask = await input.surreal.select<TaskRow>(input.parentTaskRecord);
360→  if (!parentTask) throw new Error(`parent task not found: ${input.parentTaskRecord.id}`);
361→  if ((parentTask.workspace.id as string) !== (input.workspaceRecord.id as string)) {
362→    throw new Error("parent task is outside the current workspace scope");
363→  }
364→
365→  const now = new Date();
366→  const taskRecord = new RecordId("task", randomUUID());
367→
368→  await input.surreal.create(taskRecord).content({
369→    title: input.title,
370→    status: "todo",
371→    created_at: now,
372→    updated_at: now,
373→    workspace: input.workspaceRecord,
374→    ...(input.category ? { category: input.category } : parentTask.category ? { category: parentTask.category } : {}),
375→    ...(input.rationale ? { description: input.rationale } : {}),
376→  });
377→
378→  // Create subtask_of edge
379→  await input.surreal
380→    .relate(taskRecord, new RecordId("subtask_of", randomUUID()), input.parentTaskRecord, {
381→      added_at: now,
382→    })
383→    .output("after");
384→
385→  // Copy belongs_to edges from parent (inherit project/feature)
386→  const [parentBelongsTo] = await input.surreal
387→    .query<[Array<{ out: RecordId }>]>(
388→      "SELECT out FROM belongs_to WHERE `in` = $parent;",
389→      { parent: input.parentTaskRecord },
390→    )
391→    .collect<[Array<{ out: RecordId }>]>();
392→
393→  for (const edge of parentBelongsTo) {
394→    await input.surreal
395→      .relate(taskRecord, new RecordId("belongs_to", randomUUID()), edge.out, {
396→        added_at: now,
397→      })
398→      .output("after");
399→  }
400→
401→  return {
402→    task_id: toRawId(taskRecord),
403→    parent_task_id: toRawId(input.parentTaskRecord),
404→    already_existed: false,
405→  };
406→}
