408→/** Update task status with subtask rollup */
409→export async function updateTaskStatus(input: {
410→  surreal: Surreal;
411→  workspaceRecord: RecordId<"workspace", string>;
412→  taskRecord: RecordId<"task", string>;
413→  status: string;
414→  notes?: string;
415→}): Promise<{ task_id: string; status: string; parent_status?: string }> {
416→  const now = new Date();
417→  const task = await input.surreal.select<TaskRow>(input.taskRecord);
418→  if (!task) throw new Error(`task not found: ${input.taskRecord.id}`);
419→  if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
420→    throw new Error("task is outside the current workspace scope");
421→  }
422→
423→  await input.surreal.update(input.taskRecord).merge({
424→    status: input.status,
425→    updated_at: now,
426→  });
427→
428→  if (input.notes) {
429→    // Append note to description_entries
430→    const task = await input.surreal.select<{ description_entries?: Array<{ text: string; created_at: Date }> }>(input.taskRecord);
431→    const entries = task?.description_entries ?? [];
432→    entries.push({ text: input.notes, created_at: now });
433→    await input.surreal.update(input.taskRecord).merge({ description_entries: entries });
434→  }
435→
436→  // Check if this task has a parent (subtask_of) and compute rollup
437→  const [parentRows] = await input.surreal
438→    .query<[Array<{ out: RecordId<"task", string> }>]>(
439→      "SELECT out FROM subtask_of WHERE `in` = $task LIMIT 1;",
440→      { task: input.taskRecord },
441→    )
442→    .collect<[Array<{ out: RecordId<"task", string> }>]>();
443→
444→  let parentStatus: string | undefined;
445→
446→  if (parentRows.length > 0) {
447→    const parentRecord = parentRows[0].out;
448→    parentStatus = await computeSubtaskRollup(input.surreal, parentRecord);
449→  }
450→
451→  return {
452→    task_id: toRawId(input.taskRecord),
453→    status: input.status,
454→    ...(parentStatus ? { parent_status: parentStatus } : {}),
455→  };
456→}
