496→/** Log an implementation note on an entity */
497→export async function logImplementationNote(input: {
498→  surreal: Surreal;
499→  entityTable: string;
500→  entityId: string;
501→  note: string;
502→  filesChanged?: string[];
503→}): Promise<{ entity_id: string; note_added: boolean }> {
504→  const record = new RecordId(input.entityTable, input.entityId);
505→  const entity = await input.surreal.select<{ description_entries?: Array<{ text: string; source?: RecordId; created_at: Date }> }>(record);
506→
507→  if (!entity) throw new Error(`entity not found: ${input.entityTable}:${input.entityId}`);
508→
509→  const now = new Date();
510→  const entries = entity.description_entries ?? [];
511→  const noteText = input.filesChanged?.length
512→    ? `${input.note}\n\nFiles: ${input.filesChanged.join(", ")}`
513→    : input.note;
514→
515→  entries.push({ text: noteText, created_at: now });
516→
517→  await input.surreal.update(record).merge({
518→    description_entries: entries,
519→    updated_at: now,
520→  });
521→
522→  return { entity_id: `${input.entityTable}:${input.entityId}`, note_added: true };
523→}
