567→/** End an agent session with summary */
568→export async function endAgentSession(input: {
569→  surreal: Surreal;
570→  workspaceRecord: RecordId<"workspace", string>;
571→  sessionId: string;
572→  summary: string;
573→  decisionsMade?: string[];
574→  questionsAsked?: string[];
575→  tasksProgressed?: Array<{ task_id: string; from_status: string; to_status: string }>;
576→  filesChanged?: Array<{ path: string; change_type: string }>;
577→  observationsLogged?: string[];
578→}): Promise<{ session_id: string; ended: boolean }> {
579→  const now = new Date();
580→  const sessionRecord = new RecordId("agent_session", requireRawId(input.sessionId, "session_id"));
581→  const session = await input.surreal.select<{ workspace: RecordId<"workspace", string>; ended_at?: Date; summary?: string }>(sessionRecord);
582→  if (!session) {
583→    throw new Error(`session not found: ${input.sessionId}`);
584→  }
585→  if ((session.workspace.id as string) !== (input.workspaceRecord.id as string)) {
586→    throw new Error("session is outside the current workspace scope");
587→  }
588→
589→  // Idempotent: if session already ended, return without overwriting
590→  if (session.ended_at) {
591→    return { session_id: toRawId(sessionRecord), ended: true };
592→  }
593→
594→  await input.surreal.update(sessionRecord).merge({
595→    ended_at: now,
596→    summary: input.summary,
597→    ...(input.decisionsMade?.length
598→      ? { decisions_made: input.decisionsMade.map((id) => new RecordId("decision", requireRawId(id, "decisions_made[]"))) }
599→      : {}),
600→    ...(input.questionsAsked?.length
601→      ? { questions_asked: input.questionsAsked.map((id) => new RecordId("question", requireRawId(id, "questions_asked[]"))) }
602→      : {}),
603→    ...(input.tasksProgressed?.length
604→      ? {
605→          tasks_progressed: input.tasksProgressed.map((t) => ({
606→            task_id: new RecordId("task", requireRawId(t.task_id, "tasks_progressed[].task_id")),
607→            from_status: t.from_status,
608→            to_status: t.to_status,
609→          })),
610→        }
611→      : {}),
612→    ...(input.filesChanged?.length ? { files_changed: input.filesChanged } : {}),
613→    ...(input.observationsLogged?.length
614→      ? { observations_logged: input.observationsLogged.map((id) => new RecordId("observation", requireRawId(id, "observations_logged[]"))) }
615→      : {}),
616→  });
617→
618→  // Create session -> entity edges
619→  if (input.decisionsMade?.length) {
620→    for (const decisionId of input.decisionsMade) {
621→      const rawDecisionId = requireRawId(decisionId, "decisions_made[]");
622→      await input.surreal
623→        .relate(sessionRecord, new RecordId("produced", randomUUID()), new RecordId("decision", rawDecisionId), {
624→          added_at: now,
625→        })
626→        .output("after");
627→    }
628→  }
629→
630→  if (input.questionsAsked?.length) {
631→    for (const questionId of input.questionsAsked) {
632→      const rawQuestionId = requireRawId(questionId, "questions_asked[]");
633→      await input.surreal
634→        .relate(sessionRecord, new RecordId("asked", randomUUID()), new RecordId("question", rawQuestionId), {
635→          added_at: now,
636→        })
637→        .output("after");
638→    }
639→  }
640→
641→  if (input.tasksProgressed?.length) {
642→    for (const t of input.tasksProgressed) {
643→      const rawTaskId = requireRawId(t.task_id, "tasks_progressed[].task_id");
644→      await input.surreal
645→        .relate(sessionRecord, new RecordId("progressed", randomUUID()), new RecordId("task", rawTaskId), {
646→          from_status: t.from_status,
647→          to_status: t.to_status,
648→          added_at: now,
649→        })
650→        .output("after");
651→    }
652→  }
653→
654→  return { session_id: toRawId(sessionRecord), ended: true };
655→}
656→
657→/** Log a git commit to the graph */
658→export async function logCommit(input: {
659→  surreal: Surreal;
660→  workspaceRecord: RecordId<"workspace", string>;
661→  projectRecord?: RecordId<"project", string>;
662→  sha: string;
663→  message: string;
664→  author: string;
665→  taskUpdates?: Array<{ task_id: string; new_status: string }>;
666→  relatedTaskIds?: string[];
667→  decisionsDetected?: Array<{ name: string; rationale: string }>;
668→}): Promise<{ commit_id: string; tasks_updated: number; tasks_linked: number; decisions_created: number }> {
669→  const now = new Date();
670→  const commitRecord = new RecordId("git_commit", randomUUID());
671→
672→  await input.surreal.create(commitRecord).content({
673→    sha: input.sha,
674→    message: input.message,
675→    author_name: input.author,
676→    workspace: input.workspaceRecord,
677→    authored_at: now,
678→    created_at: now,
679→  });
680→
681→  // Update task statuses
682→  let tasksUpdated = 0;
683→  if (input.taskUpdates?.length) {
684→    for (const update of input.taskUpdates) {
685→      const taskRecord = new RecordId("task", requireRawId(update.task_id, "task_updates[].task_id"));
686→      const task = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(taskRecord);
687→      if (!task) {
688→        throw new Error(`task not found: ${update.task_id}`);
689→      }
690→      if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
691→        throw new Error("task update is outside the current workspace scope");
692→      }
693→      await input.surreal.update(taskRecord).merge({
694→        status: update.new_status,
695→        updated_at: now,
696→      });
697→      tasksUpdated++;
698→    }
699→  }
700→
701→  // Link related tasks to this commit
702→  const linkedTaskIds = new Set<string>();
703→  // Include tasks from task_updates
704→  if (input.taskUpdates?.length) {
705→    for (const update of input.taskUpdates) {
706→      linkedTaskIds.add(requireRawId(update.task_id, "task_updates[].task_id"));
707→    }
708→  }
709→  // Include explicitly declared related tasks
710→  if (input.relatedTaskIds?.length) {
711→    for (const taskId of input.relatedTaskIds) {
712→      linkedTaskIds.add(requireRawId(taskId, "related_task_ids[]"));
713→    }
714→  }
715→  for (const taskId of linkedTaskIds) {
716→    const taskRecord = new RecordId("task", taskId);
717→    const task = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(taskRecord);
718→    if (!task) {
719→      throw new Error(`task not found: ${taskId}`);
720→    }
721→    if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
722→      throw new Error("task link is outside the current workspace scope");
723→    }
724→    await input.surreal
725→      .relate(taskRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
726→        commit_sha: input.sha,
727→        linked_at: now,
728→      })
729→      .output("after");
730→  }
731→
732→  // Create provisional decisions if flagged
733→  let decisionsCreated = 0;
734→  if (input.decisionsDetected?.length) {
735→    for (const decision of input.decisionsDetected) {
736→      const decisionRecord = new RecordId("decision", randomUUID());
737→      await input.surreal.create(decisionRecord).content({
738→        summary: decision.name,
739→        rationale: decision.rationale,
740→        status: "provisional",
741→        decided_by_name: "code-agent",
742→        workspace: input.workspaceRecord,
743→        source_commit: commitRecord,
744→        created_at: now,
745→        updated_at: now,
746→      });
747→
748→      // Link decision to project (if known)
749→      if (input.projectRecord) {
750→        await input.surreal
751→          .relate(decisionRecord, new RecordId("belongs_to", randomUUID()), input.projectRecord, {
752→            added_at: now,
753→          })
754→          .output("after");
755→      }
756→
757→      // Create implemented_by edge
758→      await input.surreal
759→        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
760→          commit_sha: input.sha,
761→          linked_at: now,
762→        })
763→        .output("after");
764→
765→      decisionsCreated++;
766→    }
767→  }
768→
769→  return {
770→    commit_id: toRawId(commitRecord),
771→    tasks_updated: tasksUpdated,
772→    tasks_linked: linkedTaskIds.size,
773→    decisions_created: decisionsCreated,
774→  };
775→}
776→
777→// ---------------------------------------------------------------------------
778→// MCP tool queries (flat response shapes for Brain MCP tools)
779→// ---------------------------------------------------------------------------
780→
781→type PluginTaskRow = {
782→  title: string;
783→  description?: string;
784→  status: string;
785→  priority?: string;
786→  owner_name?: string;
787→  deadline?: string | Date;
788→  workspace: RecordId<"workspace", string>;
789→};
790→
791→/** Get simple task context for plugin tools. Returns undefined if task not found or outside workspace. */
792→export async function getPluginTaskContext(input: {
793→  surreal: Surreal;
794→  workspaceRecord: RecordId<"workspace", string>;
795→  taskRecord: RecordId<"task", string>;
796→}): Promise<PluginTaskContext | undefined> {
797→  const task = await input.surreal.select<PluginTaskRow>(input.taskRecord);
798→  if (!task) return undefined;
799→  if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) return undefined;
800→
801→  return {
802→    title: task.title,
803→    status: task.status,
804→    ...(task.description ? { description: task.description } : {}),
805→    ...(task.priority ? { priority: task.priority } : {}),
806→    ...(task.owner_name ? { owner_name: task.owner_name } : {}),
807→    ...(task.deadline ? { deadline: toIso(task.deadline) } : {}),
808→  };
809→}
810→
811→type PluginProjectRow = {
812→  name: string;
813→  description?: string;
814→  status: string;
815→  workspace: RecordId<"workspace", string>;
816→};
817→
818→/** Get simple project context for plugin tools. Returns undefined if project not found or outside workspace. */
819→export async function getPluginProjectContext(input: {
820→  surreal: Surreal;
821→  workspaceRecord: RecordId<"workspace", string>;
822→  projectRecord: RecordId<"project", string>;
823→}): Promise<PluginProjectContext | undefined> {
824→  const project = await input.surreal.select<PluginProjectRow>(input.projectRecord);
825→  if (!project) return undefined;
826→  if ((project.workspace?.id as string) !== (input.workspaceRecord.id as string)) return undefined;
827→
828→  // Count tasks and features belonging to this project
829→  const [countResults] = await input.surreal
830→    .query<[Array<{ task_count: number; feature_count: number }>]>(
831→      `SELECT
832→         (SELECT count() FROM task WHERE id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project) GROUP ALL)[0].count AS task_count,
833→         (SELECT count() FROM feature WHERE id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project) GROUP ALL)[0].count AS feature_count;`,
834→      { project: input.projectRecord },
835→    )
836→    .collect<[Array<{ task_count: number; feature_count: number }>]>();
837→
838→  const counts = countResults[0];
839→
840→  return {
841→    name: project.name,
842→    status: project.status,
843→    ...(project.description ? { description: project.description } : {}),
844→    taskCount: counts?.task_count ?? 0,
845→    featureCount: counts?.feature_count ?? 0,
846→  };
847→}
848→
849→// ---------------------------------------------------------------------------
850→// Utility
851→// ---------------------------------------------------------------------------
852→
853→function levenshteinSimilarity(a: string, b: string): number {
854→  if (a === b) return 1;
855→  const longer = a.length > b.length ? a : b;
856→  const shorter = a.length > b.length ? b : a;
857→  if (longer.length === 0) return 1;
858→
859→  const costs: number[] = [];
860→  for (let i = 0; i <= longer.length; i++) {
861→    let lastValue = i;
862→    for (let j = 0; j <= shorter.length; j++) {
863→      if (i === 0) {
864→        costs[j] = j;
865→      } else if (j > 0) {
866→        let newValue = costs[j - 1];
867→        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
868→          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
869→        }
870→        costs[j - 1] = lastValue;
871→        lastValue = newValue;
872→      }
873→    }
874→    if (i > 0) costs[shorter.length] = lastValue;
875→  }
876→
877→  return (longer.length - costs[shorter.length]) / longer.length;
878→}
